/**
 * bundle-styles.js — Generate complete CSS bundle for @orion-ds/blocks
 *
 * This post-build script concatenates:
 * 1. @orion-ds/react/dist/styles.css (tokens + all react component styles)
 * 2. @orion-ds/blocks/dist/blocks.css (blocks-specific styles)
 *
 * Output: @orion-ds/blocks/dist/styles.css (complete bundle, ~590KB)
 *
 * This allows consumers to do:
 *   import '@orion-ds/blocks/styles.css';  // single import, everything included
 *
 * Instead of:
 *   import '@orion-ds/react/styles.css';
 *   import '@orion-ds/blocks/styles.css';  // two imports
 */

import { readFileSync, writeFileSync, existsSync } from 'fs';
import { resolve, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const root = resolve(__dirname, '..');
const reactDist = resolve(__dirname, '../../react/dist');

const reactStyles = resolve(reactDist, 'styles.css');
const blocksStyles = resolve(root, 'dist/blocks.css');
const output = resolve(root, 'dist/styles.css');

// Check if react/dist/styles.css exists (built first by Turbo)
if (!existsSync(reactStyles)) {
  console.error(
    'ERROR: @orion-ds/react/dist/styles.css not found.\n' +
    'This means @orion-ds/react must be built first.\n' +
    '\n' +
    'Run: npm run build:packages\n' +
    'Or:  cd packages/react && npm run build && cd ../blocks && npm run build:styles'
  );
  process.exit(1);
}

// Check if blocks/dist/blocks.css exists (generated by vite build)
if (!existsSync(blocksStyles)) {
  console.error(
    'ERROR: blocks/dist/blocks.css not found.\n' +
    'This means the Vite build did not run yet.\n' +
    '\n' +
    'Run: vite build\n' +
    'Or:  npm run build'
  );
  process.exit(1);
}

try {
  // Read both CSS files
  const react = readFileSync(reactStyles, 'utf-8');
  const blocks = readFileSync(blocksStyles, 'utf-8');

  // Concatenate with header
  const combined = [
    '/**',
    ' * @orion-ds/blocks/styles.css — Complete CSS Bundle',
    ' *',
    ' * This is the unified stylesheet for @orion-ds/blocks.',
    ' * It includes:',
    ' *   - Design tokens (colors, spacing, typography, shadows)',
    ' *   - All @orion-ds/react component styles (Section, Container, Button, etc.)',
    ' *   - All @orion-ds/blocks section styles (Hero, Features, CTA, etc.)',
    ' *',
    ' * Single import: import "@orion-ds/blocks/styles.css";',
    ' */',
    '',
    '/* ============================================================================ */',
    '/* GENERATED BY: packages/blocks/scripts/bundle-styles.js                     */',
    '/* ============================================================================ */',
    '',
    react,
    '',
    '/* ============================================================================ */',
    '/* @orion-ds/blocks sections CSS                                              */',
    '/* ============================================================================ */',
    '',
    blocks,
  ].join('\n');

  // Write output
  writeFileSync(output, combined, 'utf-8');

  const sizeKB = (combined.length / 1024).toFixed(1);
  console.log(`✓ Generated @orion-ds/blocks/dist/styles.css (${sizeKB}KB)`);
} catch (error) {
  console.error('ERROR: Failed to bundle styles:', error.message);
  process.exit(1);
}
